ELEVATION_API_KEY = os.getenv('ELEVATION_API_KEY')


DMS_PATTERN = re.compile(r"\D*(\d+)\D*(\d+)\D*(\d+\.\d+)\D*([nNsSeEwW])\D*")


@dataclass
class RouteNode:
    seqid: int
    lat: float
    lon: float
    elev: float


@dataclass
class Route:
    name: str
    units: str
    nodes: deque[RouteNode] = field(default_factory=deque[RouteNode])


def dms_to_dd(lat:str, lon:str) -> tuple[float,float] | None:
    '''Convert DMS latitude and longitude into decimal degree coordinates'''
    lat_match = re.search(DMS_PATTERN, lat)
    lon_match = re.search(DMS_PATTERN, lon)
    
    if lat_match is None or lon_match is None: 
        return None
    
    lat_items = lat_match.groups()
    lon_items = lon_match.groups()
    
    if len(lat_items) != 4 or len(lon_items) != 4:
        return None
    
    lat_dd = int(lat_items[0]) + (int(lat_items[1]) / 60) + (float(lat_items[2]) / 3600)
    lon_dd = int(lon_items[0]) + (int(lon_items[1]) / 60) + (float(lon_items[2]) / 3600)
    
    lat_dd *= -1 if lat_items[3] in 'sS' and lat_dd > 0 else 1
    lon_dd *= -1 if lon_items[3] in 'wW' and lon_dd > 0 else 1
        
    return (lat_dd, lon_dd)


def get_route_segment(api_key:str, orig:tuple[float,float], dest:tuple[float,float]) -> tuple[int,str]:
    '''Get route segment encoded polyline, and segment distance (meters)'''
    gclient = routing_v2.RoutesClient(client_options={'api_key': api_key})
    
    request = routing_v2.ComputeRoutesRequest(
        origin=routing_v2.Waypoint(
            location=routing_v2.Location(
                lat_lng=latlng_pb2.LatLng(latitude=orig[0], longitude=orig[1])
            )
        ),
        destination=routing_v2.Waypoint(
            location=routing_v2.Location(
                lat_lng=latlng_pb2.LatLng(latitude=dest[0], longitude=dest[1])
            )
        ),
        polyline_quality=routing_v2.PolylineQuality.HIGH_QUALITY,
        polyline_encoding=routing_v2.PolylineEncoding.ENCODED_POLYLINE
    )
    
    field_mask = 'routes.distanceMeters,routes.polyline.encodedPolyline'
    response = gclient.compute_routes(request=request, metadata=[('x-goog-fieldmask', field_mask)])
    
    return (response.routes[0].distance_meters, response.routes[0].polyline.encoded_polyline)


def decode_linestring(encoded_polyline:str) -> LineString:
    '''Get a GeoJSON LineString object from encoded polyline'''
    decoded = polyline.decode(encoded_polyline)
    coords = [(round(lat, 5), round(lon, 5)) for lat, lon in decoded]
    linestring = LineString(coords)
    
    return linestring


def ls_to_df(linestring:dict) -> pd.DataFrame:
    '''Get a dataframe representation of geojson linestring with added z and b column'''
    df = pd.DataFrame(linestring['coordinates'], columns=list('yx')) # lat, lon
    df.replace('NaN', 0.0)
    df[['z']] = 0.0
    
    return df


def get_elevatations(api_key:str, coords:list[tuple[float,float]]) -> dict[tuple[float,float],float]:
    '''Return a mapping of latlon pairs to their elevations'''
    gclient = googlemaps.Client(key=api_key)
    
    elevations = {}
    request = gclient.elevation(coords) # type: ignore
    
    for res in request:
        elevations[(round(res['location']['lat'], 5), round(res['location']['lng'], 5))] = round(res['elevation'], 5)
    
    return elevations


def insert_elevations(df:pd.DataFrame, data:dict[tuple[float,float],float]) -> None:
    '''Insert sample coordinate pair's elevation into coordinate DataFrame'''
    for k, v in data.items():
        df.loc[(df['x'] == k[1]) & (df['y'] == k[0]), ['z']] = v


def pchip_interpolate(df:pd.DataFrame) -> pd.DataFrame:
    '''Interpolate x, y, z positions versus distance along path'''
    x = df['x'].to_numpy()
    y = df['y'].to_numpy()
    z = df['z'].to_numpy()
    
    dx = np.diff(x)
    dy = np.diff(y)
    dz = np.diff(z)
    
    segment_lens = np.sqrt(dx**2 + dy**2 + dz**2)
    distance = np.concatenate([[0], np.cumsum(segment_lens)])
    new_distance = np.linspace(0, distance[-1], 5000)
    
    interp_x = PchipInterpolator(distance, x)
    interp_y = PchipInterpolator(distance, y)
    interp_z = PchipInterpolator(distance, z)
    
    new_x = interp_x(new_distance)
    new_y = interp_y(new_distance)
    new_z = interp_z(new_distance)
    
    fine_path = pd.DataFrame({'x': new_x, 'y': new_y, 'z': new_z})
    
    return fine_path

    

